import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate loan repayment?", a: "Loan repayment is calculated from the loan amount, monthly interest rate, and either a fixed number of monthly payments or a chosen monthly repayment amount." },
  { q: "What is a repayment schedule?", a: "A repayment schedule shows each payment, how much goes to interest, how much reduces principal, and the remaining balance after every month." },
  { q: "How does loan term affect monthly repayment?", a: "A longer term usually lowers the monthly repayment but increases total interest. A shorter term raises the monthly payment but reduces total cost." },
  { q: "What happens if you miss a loan repayment?", a: "A missed repayment may trigger late fees, extra interest, credit score damage, and possible default depending on the lender and loan terms." },
  { q: "Can you repay a loan early?", a: "Many loans allow early repayment, which can reduce total interest. Check whether your lender charges prepayment penalties." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function paymentForMonths(amount: number, apr: number, months: number) {
  const r = apr / 100 / 12;
  if (r === 0) return amount / Math.max(1, months);
  return amount * r / (1 - Math.pow(1 + r, -months));
}

function payoff(amount: number, apr: number, payment: number) {
  let balance = amount;
  let totalInterest = 0;
  const r = apr / 100 / 12;
  const schedule: { month: number; payment: number; principal: number; interest: number; balance: number }[] = [];
  for (let month = 1; month <= 1200 && balance > 0.01; month++) {
    const interest = balance * r;
    if (payment <= interest && balance > 0) return { months: Infinity, totalInterest: Infinity, totalRepaid: Infinity, schedule };
    const paid = Math.min(payment, balance + interest);
    const principal = paid - interest;
    balance = Math.max(0, balance - principal);
    totalInterest += interest;
    schedule.push({ month, payment: paid, principal, interest, balance });
  }
  return { months: schedule.length, totalInterest, totalRepaid: amount + totalInterest, schedule };
}

export default function RepaymentCalculator() {
  useCurrencyVersion();
  const [amount, setAmount] = useState(15000);
  const [apr, setApr] = useState(7);
  const [mode, setMode] = useState("months");
  const [months, setMonths] = useState(60);
  const [monthlyPayment, setMonthlyPayment] = useState(300);
  const payment = mode === "months" ? paymentForMonths(amount, apr, months) : monthlyPayment;
  const result = useMemo(() => payoff(amount, apr, payment), [amount, apr, payment]);
  const comparison = [200, 300, 400, 500, 750].map((p) => ({ payment: p, data: payoff(15000, 7, p) }));

  return (
    <>
      <SEOHead title="Free Repayment Calculator Online - Calculate Loan Repayment Schedule Instantly | CalcHive" description="Free online repayment calculator. Calculate monthly payment, repayment period and total interest for any loan amount and rate instantly. 100% free, no signup required." canonical="/repayment-calculator" keywords="free repayment calculator, loan repayment calculator free online, monthly repayment calculator free, calculate loan repayment free, debt repayment schedule calculator free" category="Financial Calculators" breadcrumbName="Free Repayment Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Repayment Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate monthly repayment, total interest, total repaid, or how long a repayment amount will take.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Loan amount</label><input type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual interest rate (%)</label><input type="number" value={apr} onChange={(e) => setApr(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value)} className={inputClass}><option value="months">Find monthly payment</option><option value="payment">Find repayment period</option></select></div>
            {mode === "months" ? <div><label className="text-sm font-semibold text-foreground block mb-2">Monthly payments</label><input type="number" value={months} onChange={(e) => setMonths(Number(e.target.value))} className={inputClass} /></div> : <div><label className="text-sm font-semibold text-foreground block mb-2">Monthly payment</label><input type="number" value={monthlyPayment} onChange={(e) => setMonthlyPayment(Number(e.target.value))} className={inputClass} /></div>}
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(payment)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Repayment period</p><p className="text-lg font-extrabold text-foreground">{Number.isFinite(result.months) ? `${result.months} mo` : "N/A"}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{money(result.totalInterest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total repayment</p><p className="text-lg font-extrabold text-foreground">{money(result.totalRepaid)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Loan Repayment Schedule for Free</h2><p className="text-muted-foreground leading-relaxed">This free repayment calculator builds a monthly schedule by applying APR interest, subtracting the repayment, and tracking the remaining loan balance.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Find the Monthly Payment for Any Repayment Period</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Repayment Schedule on $15,000 at 7% APR</caption><thead className="bg-muted/60"><tr>{["Monthly Payment", "Repayment Period", "Total Interest", "Total Repaid"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.payment}><td className="py-2.5 px-3 font-semibold">{money(row.payment)}</td><td className="py-2.5 px-3">{Number.isFinite(row.data.months) ? `${row.data.months} months` : "N/A"}</td><td className="py-2.5 px-3">{money(row.data.totalInterest)}</td><td className="py-2.5 px-3">{money(row.data.totalRepaid)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Loan Repayment Tool for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Repayment Schedule</caption><thead className="bg-muted/60"><tr>{["Month", "Payment", "Principal", "Interest", "Balance"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.schedule.slice(0, 180).map((row) => <tr key={row.month}><td className="py-2.5 px-3">{row.month}</td><td className="py-2.5 px-3">{money(row.payment)}</td><td className="py-2.5 px-3">{money(row.principal)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/repayment-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


